# Initial decomposition
goal = "Analyze market trends for AI startup pricing"
subgoals = {
    "scrape": {"task": "scrape", "deps": []},
    "analyze": {"task": "analyze", "deps": ["scrape"]},
    "write": {"task": "write", "deps": ["analyze"]}
}

for subgoal in execute_order(subgoals):  # respects dependencies
    result = execute_subtask(subgoal)
    if result.error:
        handle_error(subgoal, result.error)
    else:
        update_state(subgoal, result)

def handle_error(subgoal, error):
    if subgoal.task == "scrape" and error == "selector_not_found":
        # Re-plan: decompose into inspect → fix → retry
        new_subgoals = {
            "inspect": {"task": "inspect_html", "deps": []},
            "fix_selector": {"task": "fix_selector", "deps": ["inspect"]},
            "retry_scrape": {"task": "scrape", "deps": ["fix_selector"]}
        }
        update_dag(new_subgoals)

# Tree structure
root = {
    "goal": "Analyze market trends",
    "children": [
        {"goal": "Scrape pricing data", "children": []},
        {"goal": "Analyze trends", "children": []},
        {"goal": "Write report", "children": []}
    ]
}
